package ru.memearena.tournament.api; import org.springframework.context.annotation.*; import org.springframework.web.bind.annotation.*; import ru.memearena.tournament.application.*; import ru.memearena.tournament.infrastructure.*; import java.time.*; import java.util.*; @Profile("local") @RestController @RequestMapping("/api/v1/admin/local/tournaments") public class LocalAdminTournamentController{ private final TournamentMatchRepository matches; private final TournamentProgressionService progression; private final Clock clock; public LocalAdminTournamentController(TournamentMatchRepository m,TournamentProgressionService p,Clock c){matches=m;progression=p;clock=c;} @PostMapping("/{id}/finish-current-round") public Object finish(@PathVariable UUID id){var all=matches.findByTournamentIdOrderByRoundNumberAscMatchNumberAsc(id); int r=all.stream().mapToInt(x->x.roundNumber).max().orElse(1); all.stream().filter(x->x.roundNumber==r).forEach(x->{x.endsAt=Instant.now(clock).minusSeconds(1);}); matches.saveAll(all); return progression.advance(id);} }
